// formatCents formats cents to a currency string like "EUR 12.34".
func formatCents(amount int64, currency string) string {
	symbol := currencySymbol(currency)
	val := float64(amount) / 100.0
	return fmt.Sprintf("%s%.2f", symbol, val)
}

// formatCentsPlain formats cents without currency symbol.
func formatCentsPlain(amount int64) string {
	val := float64(amount) / 100.0
	return fmt.Sprintf("%.2f", val)
}

func currencySymbol(currency string) string {
	switch currency {
	case "EUR":
		return "\u20ac"
	case "USD":
		return "$"
	case "GBP":
		return "\u00a3"
	default:
		return currency + " "
	}
}

// isOverdue returns true if the invoice is finalized and past its due date.
func isOverdue(inv queries.InvoiceReadModel) bool {
	return inv.Status == string(domain.StatusFinalized) && time.Now().After(inv.DueDate)
}

// escapeJS escapes single quotes for safe embedding in JS string literals.
func escapeJS(s string) string {
	return strings.ReplaceAll(s, "'", "\\'")
}

